import React, { useEffect, useState } from "react";

function UserProfile() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    // გადმოვიღოთ token localStorage-დან
    const token = localStorage.getItem("auth_token");
    if (token) {
      // JSON Web Token არის base64, გავარჩიოთ payload
      const payload = JSON.parse(atob(token.split(".")[1]));
      setUser(payload);
    }
  }, []);

  const handleSignOut = () => {
    localStorage.removeItem("auth_token"); // წაშლის token-ს
    setUser(null);
    window.location.href = "/"; // დაბრუნება მთავარ გვერდზე
  };

  if (!user) {
    return <p>თქვენ ჯერ არ ხართ ავტორიზებული</p>;
  }

  return (
    <div className="user-profile">
      <img src={user.photo} alt={user.name} style={{ width: "100px", borderRadius: "50%" }} />
      <h3>გამარჯობა, {user.name}!</h3>
      <p>{user.email}</p>
      <button onClick={handleSignOut}>Sign Out</button>
    </div>
  );
}

export default UserProfile;
